-- monitor related keybinds
hl.bind(mainMod .. " + ALT + h", hl.dsp.window.move({ direction = "l" }))
hl.bind(mainMod .. " + ALT + l", hl.dsp.window.move({ direction = "r" }))
hl.bind(mainMod .. " + CTRL + ALT + h", hl.dsp.window.move({ monitor = "l" }))
hl.bind(mainMod .. " + CTRL + ALT + l", hl.dsp.window.move({ monitor = "r" }))

-- Example special workspace (scratchpad)
hl.bind(mainMod .. " + S", hl.dsp.workspace.toggle_special("magic"))
hl.bind(mainMod .. " + CTRL + S", hl.dsp.window.move({ workspace = "special:magic" }))
-- TODO: implement stuffs for scratch scratchpad
hl.bind(mainMod .. " + D", hl.dsp.workspace.toggle_special("scratch"))
hl.bind(mainMod .. " + CTRL + D", hl.dsp.window.move({ workspace = "special:scratch" }))
hl.bind(mainMod .. " + ALT + D", hl.dsp.exec_cmd("hyprctl dispatch movetoworkspace $(hyprctl activeworkspace | awk '(NR==1){print $3}')"))

-- Scroll through existing workspaces with mainMod + scroll
hl.bind(mainMod .. " + mouse_up", hl.dsp.focus({ workspace = "e+1" }))
hl.bind(mainMod .. " + mouse_down", hl.dsp.focus({ workspace = "e-1" }))
hl.bind(mainMod .. " + Tab", hl.dsp.focus({ workspace = "e+1" }))
hl.bind(mainMod .. " + SHIFT + Tab", hl.dsp.focus({ workspace = "e-1" }))
hl.bind(mainMod .. " + semicolon", hl.dsp.focus({ workspace = "previous" }))

-- Move/resize windows with mainMod + LMB/RMB and dragging
hl.bind(mainMod .. " + mouse:272", hl.dsp.window.drag())
hl.bind(mainMod .. " + mouse:273", hl.dsp.window.resize())

-- Resize windows using keyboard
hl.bind(mainMod .. " + SHIFT + left", hl.dsp.window.resize({ x = -50, y = 0, relative = true }))
hl.bind(mainMod .. " + SHIFT + right", hl.dsp.window.resize({ x = 50, y = 0, relative = true }))
hl.bind(mainMod .. " + SHIFT + up", hl.dsp.window.resize({ x = 0, y = -50, relative = true }))
hl.bind(mainMod .. " + SHIFT + down", hl.dsp.window.resize({ x = 0, y = 50, relative = true }))

-- wofi cliphist
hl.bind(mainMod .. " + CTRL + V", hl.dsp.exec_cmd(closeMenu .. " || vicinae vicinae://launch/clipboard/history"))

-- Volume and Media Control
hl.bind("XF86AudioRaiseVolume", hl.dsp.exec_cmd("pamixer -i 5 && notify-send -e -h string:x-canonical-private-synchronous:mY_N0tiF -a \"changeVolume\" -u low -i audio-volume-high -h int:value:\"$(pamixer --get-volume)\" \"Volume: $(pamixer --get-volume)%\""), { repeating = true })
hl.bind("XF86AudioLowerVolume", hl.dsp.exec_cmd("pamixer -d 5 && notify-send -e -h string:x-canonical-private-synchronous:mY_N0tiF -a \"changeVolume\" -u low -i audio-volume-high -h int:value:\"$(pamixer --get-volume)\" \"Volume: $(pamixer --get-volume)%\""), { repeating = true })
hl.bind("XF86AudioMicMute", hl.dsp.exec_cmd("pamixer --default-source -t && dunstify -h string:x-canonical-private-synchronous:m1c \"Mic is $([[ $(pamixer --default-source --get-mute) == 'true' ]] && echo 'off' || echo 'on')\""))
hl.bind("XF86AudioMute", hl.dsp.exec_cmd("pamixer -t"))
hl.bind("XF86AudioPlay", hl.dsp.exec_cmd("playerctl play-pause"))
hl.bind("XF86AudioPause", hl.dsp.exec_cmd("playerctl play-pause"))
hl.bind("XF86AudioNext", hl.dsp.exec_cmd("playerctl next"))
hl.bind("XF86AudioPrev", hl.dsp.exec_cmd("playerctl previous"))

-- brightness
hl.bind("XF86MonBrightnessDown", hl.dsp.exec_cmd(scriptsDir .. "/brightness-control.sh --dec"))
hl.bind("XF86MonBrightnessUp", hl.dsp.exec_cmd(scriptsDir .. "/brightness-control.sh --inc"))

